import React, { useState } from "react";
import { useCart } from "../context/CartContext";
import { useAuth } from "../context/AuthContext";
import "../styles/Cart.css";

const CartPage = () => {

  const { cart, removeFromCart, updateQuantity } = useCart();
  const { user } = useAuth();

  const [selectedItems, setSelectedItems] = useState([]);

  const toggleItem = (item) => {
    const exists = selectedItems.find(i =>
      i.id === item.id &&
      i.selectedSize === item.selectedSize &&
      i.selectedColor === item.selectedColor
    );

    if (exists) {
      setSelectedItems(selectedItems.filter(i =>
        !(i.id === item.id &&
          i.selectedSize === item.selectedSize &&
          i.selectedColor === item.selectedColor)
      ));
    } else {
      setSelectedItems([...selectedItems, item]);
    }
  };

  const isSelected = (item) => {
    return selectedItems.some(i =>
      i.id === item.id &&
      i.selectedSize === item.selectedSize &&
      i.selectedColor === item.selectedColor
    );
  };

  const getSelectedTotal = () => {
    return selectedItems.reduce((total, item) => {
      const price = parseFloat(item.price.replace("$", ""));
      return total + price * item.quantity;
    }, 0);
  };

  const handlePayment = async () => {

    if (selectedItems.length === 0) {
      alert("Please select items to pay");
      return;
    }

    const res = await fetch("http://localhost:5050/api/payment/create-checkout", {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        items: selectedItems,
        email: user?.email
      })
    });

    const data = await res.json();

    if (data.url) {
      window.location.href = data.url;
    }
  };

  return (
    <div className="cart-page">

      <h1>Your Cart</h1>

      {cart.items.length === 0 ? (
        <p>Your cart is empty</p>
      ) : (

        <>
          <div className="cart-items">

            {cart.items.map((item, index) => (

              <div className="cart-item" key={index}>

                <input
                  type="checkbox"
                  checked={isSelected(item)}
                  onChange={() => toggleItem(item)}
                />

                <img src={item.img} alt={item.title} />

                <div className="cart-info">
                  <h3>{item.title}</h3>
                  <p>{item.selectedSize} | {item.selectedColor}</p>
                  <p>{item.price}</p>
                </div>

                <div className="cart-quantity">

                  <button
                    onClick={() =>
                      updateQuantity(item, item.quantity - 1)
                    }
                  >
                    -
                  </button>

                  <span>{item.quantity}</span>

                  <button
                    onClick={() =>
                      updateQuantity(item, item.quantity + 1)
                    }
                  >
                    +
                  </button>

                </div>

                <button
                  className="remove-btn"
                  onClick={() => removeFromCart(item)}
                >
                  Remove
                </button>

              </div>

            ))}

          </div>

          <div className="cart-summary">

            <h2>
              Total: ${getSelectedTotal().toFixed(2)}
            </h2>

            <button
              className="pay-btn"
              onClick={handlePayment}
            >
              Pay Selected Items
            </button>

          </div>

        </>
      )}

    </div>
  );
};

export default CartPage;
